   148→  private Schema<?> createSchema() {
   149→
   150→    if (this.type.isEmpty()) {
   151→      return (this.array) ? this.arraySchema(new StringSchema())
   152→          : this.nonArraySchema(new StringSchema());
   153→    } else if (this.type.size() > 1) {
   154→      return (this.array) ? this.composedSchema() : this.nonArraySchema(new Schema<>());
   155→    }
   156→
   157→    String schemaType = getDataType(this.type.getFirst());
   158→    if (schemaType == null) {
   159→      throw new RuntimeException("property " + this.name + " type " + this.type);
   160→    }
   161→
   162→    //return (this.array) ? this.arraySchema(new Schema<>()) : this.nonArraySchema(new Schema<>());
   163→    return switch (schemaType) {
   164→      case STRING_TYPE -> (this.array) ? this.arraySchema(new StringSchema())
   165→          : this.nonArraySchema(new StringSchema());
   166→      case NUMBER_TYPE -> (this.array) ? this.arraySchema(new NumberSchema())
   167→          : this.nonArraySchema(new NumberSchema());
   168→      case INTEGER_TYPE -> (this.array) ? this.arraySchema(new IntegerSchema())
   169→          : this.nonArraySchema(new IntegerSchema());
   170→      case BOOLEAN_TYPE -> (this.array) ? this.arraySchema(new BooleanSchema())
   171→          : this.nonArraySchema(new BooleanSchema());
   172→      case DATETIME_TYPE -> (this.array) ? this.arraySchema(new DateTimeSchema())
   173→          : this.nonArraySchema(new DateTimeSchema());
   174→      default -> throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
   175→    };
   176→  }
