   178→  /**
   179→   * Generate a range of multiple values depending on the range axiom
   180→   *
   181→   * @return An ArraySchema: including a composedSchema with a list of items for anyOf, allOf restrictions.
   182→   */
   183→  private ArraySchema composedSchema() {
   184→    ArraySchema array = new ArraySchema();
   185→    Schema<?> schema;
   186→    ComposedSchema composedSchema = new ComposedSchema();
   187→    array.setDescription(description);
   188→
   189→    // Operations for managing boolean combinations
   190→    for (RestrictionInfo restriction : this.restrictions) {
   191→      for (String item : this.type) {
   192→        switch (getDataType(item)) {
   193→          case STRING_TYPE:
   194→            schema = new StringSchema();
   195→
   196→            if (item.equals("anyURI")) {
   197→              schema.format("uri");
   198→            } else if (item.equals("byte")) {
   199→              schema.format("byte");
   200→            }
   201→
   202→            break;
   203→          case NUMBER_TYPE:
   204→            schema = new NumberSchema().example(1.1);
   205→
   206→            if (item.equals("float")) {
   207→              schema.format("double");
   208→            } else if (item.equals("double")) {
   209→              schema.format("double");
   210→            } else {
   211→              schema.format("number");
   212→            }
   213→
   214→            break;
   215→          case INTEGER_TYPE:
   216→            schema = new IntegerSchema();
   217→            if (item.equals("long")) {
   218→              schema.format("int64");
   219→            }
   220→            break;
   221→          case BOOLEAN_TYPE:
   222→            schema = new BooleanSchema();
   223→            break;
   224→          case DATETIME_TYPE:
   225→            schema = withExample(new DateTimeSchema());
   226→            break;
   227→          default:
   228→            throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
   229→            //schema = new Schema<>();
   230→        }
   231→        isRequired |= restriction.impliesRequired();
   232→        switch (restriction) {
   233→          case UnionOf unionOf -> composedSchema.addAnyOfItem(withExample(schema));
   234→          case IntersectionOf intersectionOf -> composedSchema.addAllOfItem(withExample(schema));
   235→          default -> {
   236→            // Other restriction types (DataSomeValuesFrom, etc.) don't affect composed schemas
   237→            // They are handled in applySchemaRestrictions()
   238→          }
   239→        }
   240→      }
   241→    }
   242→
   243→    array.setItems(composedSchema);
   244→    return array;
   245→  }
