   151→  private OpenAPI mapApiRoot() {
   152→    String defaultIRIPrefix = Objects.requireNonNull(ontology.getFormat()).asPrefixOWLDocumentFormat()
   153→        .getDefaultPrefix();
   154→    // List of classes marked with APIRoot subclass
   155→    Set<OWLClass> apiRootClasses = ontology.getSubClassAxiomsForSubClass(manager.getOWLDataFactory()
   156→            .getOWLClass(IRI.create(defaultIRIPrefix, OntologyConstants.apiRoot))).stream()
   157→        .map(OWLSubClassOfAxiom::getSuperClass).flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
   158→        .filter(objectRestriction -> nameResolver.resolve(
   159→                objectRestriction.getProperty().asOWLObjectProperty())
   160→            .equals(OntologyConstants.hasAPI)).map(objectRestriction -> objectRestriction.getFiller().asOWLClass())
   161→        .collect(Collectors.toSet());
   162→
   163→    // Find intended root class...
   164→    OWLClass apiRootClass = config.getRootClass() != null ?
   165→        // It is specified in config, but must be marked with ApiRoot
   166→        apiRootClasses.stream().filter(WithIRI.of(IRI.create(config.getRootClass()).getShortForm())).findFirst()
   167→            .orElseThrow(() -> new RuntimeException("Not related to APIRoot: " + config.getRootClass()))
   168→        // otherwise if there's a single APIRoot assume that
   169→        : apiRootClasses.stream().reduce((a, b) -> {
   170→      throw new RuntimeException("No valid rootClass defined in config, and cannot infer from APIRoot class " +
   171→          "which has multiple API subclasses. Set rootClass to one of:\n" + String.join("\n", apiRootClasses.stream()
   172→          .map(OWLClass::getIRI).toList()));
   173→
   174→    }).orElseThrow(() -> new RuntimeException("Unable to ascertain root class for API"));
   175→
   176→    // This will be used to match all objects/properties in the schema with annotations
   177→    String schemaLabel = nameResolver.resolve(apiRootClass);
   178→    logger.info("API will be inferred from items annotated with apiLabel of " + schemaLabel);
   179→
   180→    // Set the overall api title
   181→    Info info = Optional.ofNullable(openApi.getInfo()).orElse(new Info());
   182→    info.setTitle(OntologyUtil.getTitle(apiRootClass, ontology));
   183→
   184→    // Save this value as extension for Graph tool usage whan filtering for API-specific data
   185→    info.addExtension(OpenApiConstants.X_GRL_API_LABEL, schemaLabel);
   186→
   187→    // Add extension for namespace if namespace mapping present
   188→    Optional.ofNullable(config.getNamespaceMappings())
   189→        .flatMap(stringSetMap -> stringSetMap.keySet().stream().findFirst())
   190→        .ifPresent(s -> info.addExtension(OpenApiConstants.X_GRL_GRAPH_NAMESPACE,
   191→            s.equals(DEFAULT_NS) ? defaultIRIPrefix : s));
   192→
   193→    openApi.info(info);
   194→
   195→    openApi.paths(Optional.ofNullable(openApi.getPaths()).orElse(new Paths()))
   196→        .components(Optional.ofNullable(openApi.getComponents()).orElse(new Components()));
   197→
   198→    Set<OWLClass> resourceClasses = EntitySearcher.getSuperClasses(apiRootClass, ontology)
   199→        .flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
   200→        .filter(WithIRI.onPropertyOf(OntologyConstants.hasResourceSchema)).map(HasFiller::getFiller)
   201→        .flatMap(Narrow.to(OWLClass.class)).filter(cls -> {
   202→          boolean hasApiId = EntitySearcher.getSuperClasses(cls, ontology).flatMap(Narrow.to(HasProperty.class))
   203→              .anyMatch(WithIRI.onPropertyOf(OntologyConstants.apiID));
   204→          if (!hasApiId)
   205→            logger.warning(cls + " is marked as hasResourceSchema for " + apiRootClass + " but does not have an " +
   206→                "apiID" + " property and will not be added to the API");
   207→          return hasApiId;
   208→        }).collect(Collectors.toSet());
   209→
   210→    // Create long-lived context for this mapping
   211→    context = new MappingContext(defaultIRIPrefix, ontology, Objects.requireNonNull(schemaLabel), apiRootClass,
   212→        resourceClasses, config);
   213→
   214→    resourceClasses.forEach(this::mapToPathItems);
   215→
   216→    return openApi;
   217→  }
