   219→  private void mapToPathItems(OWLClass resourceClass) {
   220→    String name = nameResolver.resolve(resourceClass);
   221→    SetMultimap<String, String> annotations = OntologyUtil.annotationsOf(resourceClass, ontology);
   222→    String prefLabel = StringUtils.defaultIfBlank(String.join(",", annotations.get("prefLabel")),
   223→        name);
   224→    String definition = OntologyUtil.getDescription(resourceClass, ontology);
   225→    PathItem singlePath = deepCopy(config.getTemplates().getSinglePathItem(), PathItem.class);
   226→    singlePath.setSummary("Single " + StringUtils.defaultIfBlank(prefLabel, name));
   227→    singlePath.setDescription(definition);
   228→    String parameterName = name + "Id";
   229→    openApi.addTagsItem(new Tag().name(name).description(definition));
   230→    Content resourceContent = new Content().addMediaType("application/json",
   231→        new MediaType().schema(new ComposedSchema().$ref(name)));
   232→    final Set<String> security = securityGroupsForResource(resourceClass);
   233→    Stream.of(PathItem.HttpMethod.GET, PathItem.HttpMethod.PUT, PathItem.HttpMethod.PATCH, PathItem.HttpMethod.DELETE)
   234→        .forEach(httpMethod -> {
   235→              Operation defaultOperation = singlePath.readOperationsMap().getOrDefault(httpMethod, new Operation());
   236→          defaultOperation.addParametersItem(new Parameter().name(parameterName).in("path").schema(new StringSchema()))
   237→                  .getResponses()
   238→                  .addApiResponse("200", new ApiResponse().description("Existing " + name).content(resourceContent));
   239→          mapToSecurityItems(name, httpMethod, security).forEach(defaultOperation::addSecurityItem);
   240→            }
   241→        );
   242→    singlePath.getPut().requestBody(new RequestBody().content(resourceContent));
   243→    singlePath.getPatch().requestBody(new RequestBody().content(resourceContent));
   244→    openApi.getPaths().addPathItem("/" + name + "/{" + parameterName + "}", singlePath);
   245→
   246→    // Add GET to collection path for fetching list of resources
   247→    PathItem collectionPath = deepCopy(config.getTemplates().getCollectionPathItem(), PathItem.class);
   248→    collectionPath.setSummary("Collection of " + prefLabel);
   249→    collectionPath.setDescription(definition);
   250→    Operation getCollection = collectionPath.readOperationsMap().getOrDefault(PathItem.HttpMethod.GET, new Operation());
   251→    getCollection.addParametersItem(new Parameter().name("start").in("query").description("Index of start item")
   252→            .schema(new IntegerSchema()))
   253→        .addParametersItem(new Parameter().name("limit").in("query").description("Maximum items to return")
   254→            .schema(new IntegerSchema())).getResponses()
   255→        .addApiResponse("200", new ApiResponse().description(name + " Collection")
   256→            .content(new Content().addMediaType("application/json",
   257→                new MediaType().schema(new ObjectSchema().properties(Map.of("totalItems", new IntegerSchema().description("Collection of returned " + name + "items")
   258→                    .example(3), "items", new ArraySchema().items(new ComposedSchema().$ref(name))))))));
   259→    mapToSecurityItems(name, PathItem.HttpMethod.GET, security).forEach(getCollection::addSecurityItem);
   260→
   261→    // Add POST to collection path for creating resource
   262→    Operation postCollection = collectionPath.readOperationsMap()
   263→        .getOrDefault(PathItem.HttpMethod.POST, new Operation());
   264→    postCollection.requestBody(new RequestBody().content(resourceContent)).getResponses()
   265→        .addApiResponse("201",
   266→            new ApiResponse().description("New " + name).content(resourceContent));
   267→    mapToSecurityItems(name, PathItem.HttpMethod.POST, security).forEach(postCollection::addSecurityItem);
   268→
   269→    mapToComponentSchemas(resourceClass, name, definition);
   270→    openApi.getPaths().addPathItem("/" + name, collectionPath);
   271→
   272→    // Tag all operations for this entity for
   273→    singlePath.readOperationsMap()
   274→        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/single/" + method));
   275→    collectionPath.readOperationsMap()
   276→        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/collection/" + method));
   277→  }
   278→
   279→  /**
   280→   * Determine the security groups associated with the given resource class. If security annotations are present on the
   281→   * resource class's restriction for this API they are returned, otherwise a default group of the form
   282→   * apiName:resourceName is returned
   283→   *
   284→   * @param resourceClass class representing api resource
   285→   * @return set of groups found
   286→   */
   287→  private Set<String> securityGroupsForResource(OWLClass resourceClass) {
   288→    return ontology.subClassAxiomsForSubClass(context.getApiRootClass())
   289→        .filter(owlSubClassOfAxiom -> owlSubClassOfAxiom.getSuperClass() instanceof OWLQuantifiedObjectRestriction restriction && restriction.getFiller()
   290→            .isOWLClass() && restriction.getFiller().asOWLClass().equals(resourceClass)
   291→            && nameResolver.resolve(restriction.getProperty()
   292→                .asObjectPropertyExpression().getNamedProperty())
   293→            .equals(OntologyConstants.hasResourceSchema)).findFirst()
   294→        .map(owlSubClassOfAxiom -> OntologyUtil.annotationsOf(owlSubClassOfAxiom).get(OntologyConstants.security))
   295→        .orElse(Collections.emptySet());
   296→
   297→  }
   298→
   299→  /**
   300→   * Return security items, if any, to associate with a method of the given type for a resource. Each security
   301→   * annotation will generate a security requirement in the api spec for each method. Template from
   302→   * config.securityTemplate will be used to generate the security requirement.<br/>
   303→   * If there is no security scheme in effect, or of no groups are given this stream will be empty, and the
   304→   * defaultSecurityTemplate value will be used from the config<br/>
   305→   * security requirements can contain placeholders which will be replaced in the generated openapi spec:
   306→   * {api} the name of the api (config.name)
   307→   * {action} mapped for each http method being generated from the config.securityActionMappings
   308→   * {model} The resource (model) name for each api resource being generated
   309→   * {security} the security string as obtained from the "security" annotation
   310→   *
   311→   * @param name  name of resource being mapped
   312→   * @param method   being mapped
   313→   * @param security groups the resource belongs to
   314→   * @return SecurityItems
   315→   */
   316→  private Stream<SecurityRequirement> mapToSecurityItems(String name, PathItem.HttpMethod method,
   317→                                                         Set<String> security) {
   318→    // If apiKey is enabled, add this as a requirement
   319→    Stream.Builder<SecurityRequirement> requirements = Stream.builder();
   320→    config.getApiKeySecuritySchemaName()
   321→        .ifPresent(s -> requirements.add(new SecurityRequirement().addList(s)));
   322→
   323→    // oauth2 scheme - add requirment groups for these
   324→    config.getOAuth2SecuritySchemeName().ifPresent(oauthSchemeName -> {
   325→      String template =
   326→          security.isEmpty() ? config.getDefaultSecurityTemplate() : config.getSecurityTemplate();
   327→      if (StringUtils.isEmpty(template)) {
   328→        // no scoped requirements, auth alone is sufficient
   329→        requirements.add(new SecurityRequirement().addList(oauthSchemeName));
   330→      } else {
   331→        // Map scoped requirements
   332→        Map<String, String> replacements = Map.of("api", config.getName(), // name of api
   333→            "action", config.getSecurityActionMappings()
   334→                .getOrDefault(method, ""), // action, mapped from path's http method,
   335→            "model", name // current path's model/resource
   336→        );
   337→        List<String> securityRequirements =
   338→            Stream.of(security, // multiple security names maye be provided
   339→                    List.of("") // non if default
   340→                ).flatMap(Collection::stream)
   341→                .map(s -> new StringSubstitutor(
   342→                    key -> key.equals("security") ? s : replacements.getOrDefault(key, ""), "{",
   343→                    "}", '\'').setEnableSubstitutionInVariables(
   344→                        true) // security annotations can contain replacements
   345→                    .replace(template)).filter(requirement -> {
   346→                  boolean valid = OAUTH_SCOPE_PATTERN.matcher(requirement).matches();
   347→                  if (!valid) {
   348→                    logger.warning(String.format(
   349→                        "%s (%s) security requirement generated ignored (must match " + "https" +
   350→                            "://datatracker.ietf.org/doc/html/rfc6749#section-3.3 scope_token): %s",
   351→                        name, method, requirement));
   352→                  }
   353→                  return valid;
   354→                }).toList();
   355→        securityRequirements.stream().map(
   356→            securityRequirement -> new SecurityRequirement().addList(oauthSchemeName,
   357→                securityRequirement)).forEach(requirements::add);
   358→      }
   359→    });
   360→    return requirements.build();
   361→  }
   362→
   363→  private void mapToComponentSchemas(OWLClass resourceClass, String name, String definition) {
   364→
   365→    ResourceSchemaMapper schemaMapper = new ResourceSchemaMapper(context, resourceClass, definition);
   366→    Map<String, Schema> schemas = openApi.getComponents()
   367→        .schemas(Optional.ofNullable(openApi.getComponents().getSchemas()).orElse(new LinkedHashMap<>())).getSchemas();
   368→    schemas.put(name, schemaMapper.getSchema());
   369→    schemas.putAll(context.getSchemaByRef());
   370→  }
   371→
   372→  private static <T> T deepCopy(T src, Class<T> cls) {
   373→    ObjectMapper mapper = Json.mapper().setSerializationInclusion(Include.NON_NULL);
   374→    try {
   375→      return mapper.readValue(mapper.writeValueAsString(src), cls);
   376→    } catch (JsonProcessingException e) {
   377→      throw new RuntimeException(e);
   378→    }
   379→  }
   380→}
