   392→      }
   393→    } else {
   394→      for (OWLClassExpression range : ranges) {
   395→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   396→        if (rangeClasses.size() != 1) {
   397→          range.accept(this);
   398→        } else if (!range.asOWLClass().equals(owlThing)) {
   399→          // Range is tracked in objectPropertyRanges via visitor methods
   400→        } else {
   401→          logger.fine("Ignoring owl:Thing range " + propertyName);
   402→        }
   403→      }
   404→    }
   405→    propertyName = "";
   406→  }
   407→
   408→  private void setBooleanCombinationDataProperties(OWLDataRange expression,
   409→      Set<OWLDataRange> ranges,
   410→      Set<OWLDataProperty> properties) {
   411→    if (propertyName.isEmpty()) {
   412→      for (OWLDataProperty property : properties) {
   413→        propertyName = cleanName(nameResolver.resolve(property));
   414→        dataPropertyNames.add(propertyName);
   415→        for (OWLDataRange range : ranges) {
   416→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   417→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   418→              range.accept(this);
   419→            }
   420→          }
   421→        }
   422→      }
   423→
   424→      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
   425→        propertyName = cleanName(nameResolver.resolve(property));
   426→        objectPropertyNames.add(propertyName);
   427→        for (OWLDataRange range : ranges) {
   428→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   429→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   430→              range.accept(this);
   431→            }
   432→          }
   433→        }
   434→      }
   435→    } else {
   436→      for (OWLDataRange range : ranges) {
   437→        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
   438→        if (rangeDatatypes.size() != 1) {
   439→          range.accept(this);
   440→        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
   441→          // Range is tracked in dataPropertyRanges via visitor methods
   442→        } else {
   443→          logger.fine("Ignoring owl:Thing range " + propertyName);
   444→        }
   445→      }
   446→    }
   447→    propertyName = "";
   448→  }
   449→
   450→  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
   451→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   452→      propertyName = cleanName(nameResolver.resolve(property));
   453→      dataPropertyNames.add(propertyName);
   454→
   455→      final String propName = propertyName;
   456→      RestrictionInfo.from(ce).ifPresent(info ->
   457→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   458→
   459→      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
   460→        dataPropertyRanges.put(propertyName, datatype);
   461→      }
   462→    }
   463→    propertyName = "";
   464→  }
   465→
   466→  // Getters for type-safe storage (unmodifiable views)
   467→  public Map<String, Set<RestrictionInfo>> getRestrictions() {
   468→    return Collections.unmodifiableMap(restrictions);
   469→  }
   470→
   471→  public Multimap<String, OWLClass> getObjectPropertyRanges() {
   472→    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
   473→  }
   474→
   475→  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
   476→    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
   477→  }
   478→
   479→  public Set<String> getObjectPropertyNames() {
   480→    return Collections.unmodifiableSet(objectPropertyNames);
   481→  }
   482→
   483→  public Set<String> getDataPropertyNames() {
   484→    return Collections.unmodifiableSet(dataPropertyNames);
   485→  }
   486→
   487→  private static String cleanName(String propertyName) {
   488→    return Objects.requireNonNull(propertyName);
   489→  }
   490→}

